1:// SPDX-License-Identifier: BUSL-1.1
2:pragma solidity 0.8.26;
4:import {IGPV2CompatibleAuction} from "src/interfaces/IGPV2CompatibleAuction.sol";
5:import {IGPV2Settlement} from "src/interfaces/IGPV2Settlement.sol";
7:import {BaseAuction} from "src/BaseAuction.sol";
8:import {Errors} from "src/libraries/Errors.sol";
9:import {Roles} from "src/libraries/Roles.sol";
11:import {GPv2Order} from "@cowprotocol/libraries/GPv2Order.sol";
12:import {IERC1271} from "@openzeppelin/contracts/interfaces/IERC1271.sol";
13:import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
14:import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
16:/// @title GPV2 Compatible Auction v1.0.0 Contract.
17:/// @notice This contract extends the BaseAuction contract to provide compatibility with CowProtocol settlement contract
18:/// via EIP-1271 signed orders.
19:contract GPV2CompatibleAuction is BaseAuction, IERC1271, IGPV2CompatibleAuction {
20:  using SafeERC20 for IERC20;
22:  /// @notice This event is emitted when the CowSwap vault relayer address is set.
23:  /// @param cowSwapVaultRelayer The address of the CowSwap vault relayer.
24:  event GPV2VaultRelayerSet(address indexed cowSwapVaultRelayer);
25:  /// @notice This event is emitted when the GPv2Settlement contract address is set.
26:  /// @param gpV2Settlement The address of the GPv2Settlement contract.
27:  event GPV2SettlementSet(address indexed gpV2Settlement);
29:  /// @notice This error is thrown when the CowProtocol order ID does not match the order details.
30:  /// @param orderId The CowProtocol order ID.
31:  error InvalidOrderId(bytes32 orderId);
32:  /// @notice This error is thrown when the verified CowProtocol order's buy token is not the configured asset out.
33:  /// @param buyToken The CowProtocol order's buy token.
34:  /// @param assetOut The address of the configured asset out.
35:  error InvalidBuyToken(address buyToken, address assetOut);
36:  /// @notice This error is thrown when the verified CowProtocol order's receiver is not the configured asset out
37:  /// receiver.
38:  /// @param receiver The CowProtocol order's receiver.
39:  /// @param assetOutReceiver The address of the configured asset out receiver.
40:  error InvalidReceiver(address receiver, address assetOutReceiver);
41:  /// @notice This error is thrown when there are insufficient assets in balance to settle the CowProtocol order.
42:  /// @param assetIn The CowProtocol order's sell token.
43:  /// @param amountIn The requested amount (sell token).
44:  /// @param assetInBalance The available balance of the asset.
45:  error InsufficientAssetInBalance(address assetIn, uint256 amountIn, uint256 assetInBalance);
46:  /// @notice This error is thrown when the CowProtocol order's buy amount is lower than the current auction price.
47:  /// @param amountOut The requested amount of asset out (buy amount).
48:  /// @param minAmountOut The minimum required amount of asset out.
49:  error InsufficientBuyAmount(uint256 amountOut, uint256 minAmountOut);
50:  /// @notice This error is thrown when the CowProtocol order is expired.
51:  /// @param validTo The order's valid to timestamp.
52:  /// @param currentTime The current block timestamp.
53:  error ExpiredOrder(uint32 validTo, uint256 currentTime);
54:  /// @notice This error is thrown when the CowProtocol order fee amount is non-zero.
55:  error InvalidFeeAmount();
56:  /// @notice This error is thrown when the CowProtocol order kind is not a sell order.
57:  /// @param orderKind The order kind.
58:  error InvalidOrderKind(bytes32 orderKind);
59:  /// @notice This error is thrown when the CowProtocol order is not partially fillable.
60:  error OrderNotPartiallyFillable();
61:  /// @notice This error is thrown when the CowProtocol order does not use direct ERC20 balances.
62:  error InvalidTokenBalanceMarker();
64:  /// @notice The CowSwap vault relayer address.
65:  address private immutable i_gpV2VaultRelayer;
66:  /// @notice The GPv2Settlement contract address.
67:  IGPV2Settlement private immutable i_gpV2Settlement;
69:  constructor(
70:    BaseAuction.ConstructorParams memory params,
71:    address gpV2VaultRelayer,
72:    address gpV2Settlement
73:  ) BaseAuction(params) {
74:    if (gpV2VaultRelayer == address(0) || gpV2Settlement == address(0)) {
75:      revert Errors.InvalidZeroAddress();
76:    }
78:    i_gpV2VaultRelayer = gpV2VaultRelayer;
79:    i_gpV2Settlement = IGPV2Settlement(gpV2Settlement);
81:    emit GPV2VaultRelayerSet(gpV2VaultRelayer);
82:    emit GPV2SettlementSet(gpV2Settlement);
83:  }
85:  /// @inheritdoc BaseAuction
86:  function _onAuctionStart(
87:    address asset
88:  ) internal override {
89:    super._onAuctionStart(asset);
91:    // Approve the CowSwap vault relayer to transfer the auctioned asset.
92:    IERC20(asset).forceApprove(i_gpV2VaultRelayer, IERC20(asset).balanceOf(address(this)));
93:  }
95:  /// @inheritdoc BaseAuction
96:  function _onAuctionEnd(
97:    address asset,
98:    bool hasFeeAggregator
99:  ) internal override {
100:    super._onAuctionEnd(asset, hasFeeAggregator);
102:    /// Revoke the CowSwap vault relayer's allowance to transfer the auctioned asset.
103:    IERC20(asset).forceApprove(i_gpV2VaultRelayer, 0);
104:  }
106:  /// @inheritdoc IERC1271
107:  /// @dev precondition - The function must not be reentered from the bid() function.
108:  /// @dev precondition - The order ID must match the provided hash.
109:  /// @dev precondition - The signature must decode to a valid GPv2Order.Data struct.
110:  /// @dev precondition - The order's sell token must be a valid auction.
111:  /// @dev precondition - The order's buy token must be the configured asset out.
112:  /// @dev precondition - The order's receiver must be the auction contract.
113:  /// @dev precondition - The contract must have sufficient approved balance of the order's sell token to cover the sell
114:  /// amount.
115:  /// @dev precondition - The order's buy amount must be greater than or equal to the current auction price.
116:  /// @dev precondition - The order must not be expired.
117:  /// @dev precondition - The order kind must be a sell order.
118:  /// @dev precondition - The order must be partially fillable.
119:  function isValidSignature(
120:    bytes32 hash,
121:    bytes memory signature
122:  ) external view whenNotPaused returns (bytes4 magicValue) {
123:    GPv2Order.Data memory order = abi.decode(signature, (GPv2Order.Data));
125:    if (s_entered) {
126:      revert Errors.ReentrantCall();
127:    }
128:    if (hash != GPv2Order.hash(order, i_gpV2Settlement.domainSeparator())) {
129:      revert InvalidOrderId(hash);
130:    }
131:    uint256 auctionStart = s_auctionStarts[address(order.sellToken)];
132:    if (auctionStart == 0) {
133:      revert InvalidAuction(address(order.sellToken));
134:    }
135:    if (address(order.buyToken) != s_assetOut) {
136:      revert InvalidBuyToken(address(order.buyToken), s_assetOut);
137:    }
138:    if (order.receiver != address(this)) {
139:      revert InvalidReceiver(order.receiver, address(this));
140:    }
141:    if (order.sellAmount == 0) {
142:      revert Errors.InvalidZeroAmount();
143:    }
144:    uint256 assetInBalance = order.sellToken.balanceOf(address(this));
145:    if (order.sellAmount > assetInBalance) {
146:      revert InsufficientAssetInBalance(address(order.sellToken), order.sellAmount, assetInBalance);
147:    }
148:    uint256 elapsedTime = block.timestamp - auctionStart;
149:    AssetParams memory assetParams = s_assetParams[address(order.sellToken)];
150:    if (elapsedTime > assetParams.auctionDuration) {
151:      revert InvalidAuction(address(order.sellToken));
152:    }
153:    (uint256 sellTokenUsdPrice,,) = _getAssetPrice(address(order.sellToken), true);
154:    uint256 minBuyAmount = _getAssetOutAmount(assetParams, sellTokenUsdPrice, order.sellAmount, elapsedTime, true);
155:    if (order.buyAmount < minBuyAmount) {
156:      revert InsufficientBuyAmount(order.buyAmount, minBuyAmount);
157:    }
158:    if (order.validTo < block.timestamp) {
159:      revert ExpiredOrder(order.validTo, block.timestamp);
160:    }
