145:    if (order.sellAmount > assetInBalance) {
146:      revert InsufficientAssetInBalance(address(order.sellToken), order.sellAmount, assetInBalance);
147:    }
148:    uint256 elapsedTime = block.timestamp - auctionStart;
149:    AssetParams memory assetParams = s_assetParams[address(order.sellToken)];
150:    if (elapsedTime > assetParams.auctionDuration) {
151:      revert InvalidAuction(address(order.sellToken));
152:    }
153:    (uint256 sellTokenUsdPrice,,) = _getAssetPrice(address(order.sellToken), true);
154:    uint256 minBuyAmount = _getAssetOutAmount(assetParams, sellTokenUsdPrice, order.sellAmount, elapsedTime, true);
