173:    }
175:    return IERC1271.isValidSignature.selector;
176:  }
178:  /// @inheritdoc IGPV2CompatibleAuction
179:  /// @dev precondition - the caller must have the ORDER_MANAGER_ROLE.
180:  function invalidateOrders(
