2:pragma solidity 0.8.26;
4:import {ITypeAndVersion} from "@chainlink/contracts/src/v0.8/shared/interfaces/ITypeAndVersion.sol";
5:import {IAuctionCallback} from "src/interfaces/IAuctionCallback.sol";
6:import {IBaseAuction} from "src/interfaces/IBaseAuction.sol";
8:import {Caller} from "src/Caller.sol";
9:import {PausableWithAccessControl} from "src/PausableWithAccessControl.sol";
10:import {Common} from "src/libraries/Common.sol";
11:import {Errors} from "src/libraries/Errors.sol";
12:import {Roles} from "src/libraries/Roles.sol";
14:import {IERC20} from "@openzeppelin/contracts/interfaces/IERC20.sol";
15:import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
16:import {IERC165} from "@openzeppelin/contracts/utils/introspection/IERC165.sol";
18:/// @title Auction Bidder v1.0.0 Contract.
19:/// @notice This contract is responsible for bidding on auctions and executing arbitrary logic to solve the auction.
20:contract AuctionBidder is PausableWithAccessControl, Caller, IAuctionCallback, ITypeAndVersion {
21:  using SafeERC20 for IERC20;
23:  /// @notice This event is emitted when the auction contract is set.
24:  /// @param auction The address of the auction contract.
25:  event AuctionContractSet(address indexed auction);
26:  /// @notice This event is emitted when the receiver address is set.
27:  /// @param receiver The address of the receiver.
28:  event ReceiverSet(address indexed receiver);
30:  /// @notice This error is thrown when an invalid auction contract is provided.
31:  error InvalidAuctionContract(address auction);
33:  /// @inheritdoc ITypeAndVersion
34:  string public constant override typeAndVersion = "AuctionBidder 1.0.0-dev";
36:  /// @notice The auction contract.
37:  IBaseAuction private s_auction;
39:  /// @notice Optional receiver address. This address will receive any leftover funds after bidding.
40:  address private s_receiver;
42:  constructor(
43:    uint48 adminRoleTransferDelay,
44:    address admin,
45:    address auction,
46:    address receiver
47:  ) PausableWithAccessControl(adminRoleTransferDelay, admin) {
48:    _setAuction(auction);
50:    if (receiver != address(0)) {
51:      _setReceiver(receiver);
52:    }
53:  }
55:  // ================================================================================================
56:  // │                                    Auction Participation                                     │
57:  // ================================================================================================
59:  /// @notice Bids on the auction contract and optionally executes arbitrary pre-bid logic.
60:  /// @dev precondition - the contract must not be paused.
61:  /// @dev precondition - the caller must have the AUCTION_BIDDER_ROLE.
62:  /// @param assetIn The address of the asset to bid with.
63:  /// @param amount The amount of the asset to bid.
64:  /// @param solution The list of calls to execute to solve the bid.
65:  function bid(
66:    address assetIn,
67:    uint256 amount,
68:    Call[] calldata solution
69:  ) external whenNotPaused onlyRole(Roles.AUCTION_BIDDER_ROLE) {
70:    IBaseAuction auction = s_auction;
71:    address assetOut = auction.getAssetOut();
73:    bytes memory data;
75:    if (solution.length > 0) {
76:      data = abi.encode(solution);
77:    } else {
78:      IERC20(assetOut).forceApprove(address(auction), s_auction.getAssetOutAmount(assetIn, amount, block.timestamp));
79:    }
81:    auction.bid(assetIn, amount, data);
83:    uint256 assetOutBalance = IERC20(assetOut).balanceOf(address(this));
85:    if (assetOutBalance > 0) {
86:      address receiver = s_receiver;
88:      if (receiver != address(0)) {
89:        IERC20(assetOut).safeTransfer(receiver, assetOutBalance);
90:      }
91:    }
92:  }
94:  /// @inheritdoc IAuctionCallback
95:  /// @dev precondition - the contract must not be paused.
96:  /// @dev precondition - the caller must be the auction contract.
97:  function auctionCallback(
98:    address from,
99:    address assetOut,
100:    uint256 amountOut,
101:    bytes calldata data
102:  ) external whenNotPaused {
103:    if (msg.sender != address(s_auction) || from != address(this)) {
104:      revert Errors.AccessForbidden();
105:    }
107:    (Call[] memory calls) = abi.decode(data, (Call[]));
109:    _multiCall(calls);
111:    IERC20(assetOut).forceApprove(msg.sender, amountOut);
112:  }
114:  /// @notice Withdraws any tokens from the contract.
115:  /// @dev precondition - the caller must have the DEFAULT_ADMIN_ROLE.
116:  /// @dev precondition - the `to` address must not be the zero address.
117:  /// @param assetAmounts The asset and amounts to withdraw.
118:  /// @param to The address to send the withdrawn tokens to.
119:  function withdraw(
120:    Common.AssetAmount[] calldata assetAmounts,
121:    address to
122:  ) external onlyRole(DEFAULT_ADMIN_ROLE) {
123:    if (to == address(0)) {
124:      revert Errors.InvalidZeroAddress();
125:    }
127:    for (uint256 i = 0; i < assetAmounts.length; ++i) {
128:      Common.AssetAmount memory assetAmount = assetAmounts[i];
129:      IERC20(assetAmount.asset).safeTransfer(to, assetAmount.amount);
130:    }
131:  }
133:  // ================================================================================================
134:  // │                                        Configuration                                         │
135:  // ================================================================================================
137:  /// @notice Sets the auction contract.
138:  /// @dev precondition - the caller must have the DEFAULT_ADMIN_ROLE.
139:  /// @param auction The address of the auction contract.
140:  function setAuction(
141:    address auction
142:  ) external onlyRole(DEFAULT_ADMIN_ROLE) {
143:    _setAuction(auction);
144:  }
146:  /// @notice Internal function to set the auction contract.
147:  /// @dev precondition - the auction address must not be zero.
148:  /// @dev precondition - the auction contract must implement the IBaseAuction interface.
149:  /// @param auction The address of the auction contract.
150:  function _setAuction(
151:    address auction
152:  ) private {
153:    if (auction == address(0)) {
154:      revert Errors.InvalidZeroAddress();
155:    }
156:    if (!IERC165(auction).supportsInterface(type(IBaseAuction).interfaceId)) {
157:      revert InvalidAuctionContract(auction);
158:    }
159:    if (address(s_auction) == auction) {
160:      revert Errors.ValueNotUpdated();
161:    }
163:    s_auction = IBaseAuction(auction);
165:    emit AuctionContractSet(auction);
166:  }
168:  /// @notice Sets the receiver address.
169:  /// @dev precondition - the caller must have the DEFAULT_ADMIN_ROLE.
170:  /// @param receiver The address of the receiver.
171:  function setReceiver(
172:    address receiver
173:  ) external onlyRole(DEFAULT_ADMIN_ROLE) {
174:    _setReceiver(receiver);
175:  }
177:  /// @notice Internal function to set the receiver address.
178:  /// @dev precondition - the receiver address must be different from the current one.
179:  /// @param receiver The address of the receiver.
180:  function _setReceiver(
181:    address receiver
182:  ) private {
183:    if (receiver == s_receiver) {
184:      revert Errors.ValueNotUpdated();
185:    }
187:    s_receiver = receiver;
189:    emit ReceiverSet(receiver);
190:  }
192:  // ================================================================================================
193:  // │                                           Getters                                            │
194:  // ================================================================================================
196:  /// @notice Getter function to retrieve the auction contract address.
197:  /// @return auction The address of the auction contract.
198:  function getAuction() external view returns (IBaseAuction auction) {
199:    return s_auction;
200:  }
202:  /// @notice Getter function to retrieve the receiver address.
203:  /// @return receiver The address of the receiver.
204:  function getReceiver() external view returns (address receiver) {
205:    return s_receiver;
206:  }
208:  /// @inheritdoc IERC165
209:  function supportsInterface(
210:    bytes4 interfaceId
211:  ) public view virtual override returns (bool) {
212:    return interfaceId == type(IAuctionCallback).interfaceId || super.supportsInterface(interfaceId);
213:  }
214:}

